"""Data access layer for task tracker."""
from datetime import datetime

# In-memory storage
_tasks = {}
_assignments = {}
_next_id = 1


def reset():
    """Reset all storage (for testing)."""
    global _tasks, _assignments, _next_id
    _tasks = {}
    _assignments = {}
    _next_id = 1


def insert_task(title, priority, due_date, status="open"):
    """Insert a new task. Returns task_id."""
    global _next_id
    task_id = _next_id
    _next_id += 1
    _tasks[task_id] = {
        "id": task_id,
        "title": title,
        "priority": priority,
        "due_date": due_date,
        "status": status,
        "created_at": datetime.now().isoformat(),
    }
    return task_id


def get_task(task_id):
    """Get a single task by ID."""
    return _tasks.get(task_id)


def get_all_tasks():
    """Get all tasks as a list."""
    return list(_tasks.values())


def get_tasks_sorted_by_priority():
    """Return tasks sorted by priority (highest first).
    Priority values: high, medium, low.
    """
    # BUG 1: Sorts alphabetically by priority string.
    # Alphabetical order: high, low, medium — puts 'low' before 'medium'!
    tasks = list(_tasks.values())
    tasks.sort(key=lambda t: t["priority"])
    return tasks


def get_tasks_by_status(status):
    """Return tasks matching the given status.
    Should do case-insensitive matching.
    """
    # BUG 2: Uses exact string match (case-sensitive).
    # Routes pass status from user input which may have different casing.
    tasks = list(_tasks.values())
    return [t for t in tasks if t["status"] == status]


def delete_task(task_id):
    """Delete a task by ID."""
    if task_id in _tasks:
        del _tasks[task_id]
        # BUG 5: Does not clean up assignments for this task
        return True
    return False


def update_task_status(task_id, status):
    """Update a task's status."""
    if task_id in _tasks:
        _tasks[task_id]["status"] = status
        return True
    return False


def assign_user(task_id, user):
    """Assign a user to a task."""
    if task_id not in _tasks:
        return False
    if task_id not in _assignments:
        _assignments[task_id] = []
    # BUG 3: No deduplication check — allows duplicate assignments
    _assignments[task_id].append(user)
    return True


def unassign_user(task_id, user):
    """Remove a user assignment from a task."""
    if task_id in _assignments and user in _assignments[task_id]:
        _assignments[task_id].remove(user)
        return True
    return False


def get_assignments(task_id):
    """Get all users assigned to a task."""
    return list(_assignments.get(task_id, []))


def get_all_assignments():
    """Get all assignments as {task_id: [users]} dict."""
    return dict(_assignments)

