"""Business logic layer for task tracker."""
from datetime import datetime, date
import db


def create_task(title, priority, due_date, status="open"):
    """Create a new task with validation."""
    if not title or not title.strip():
        raise ValueError("Title cannot be empty")
    if priority not in ("high", "medium", "low"):
        raise ValueError(f"Invalid priority: {priority}")
    return db.insert_task(title.strip(), priority, due_date, status)


def get_task(task_id):
    """Get a task by ID."""
    task = db.get_task(task_id)
    if task is None:
        raise KeyError(f"Task {task_id} not found")
    return task


def list_tasks():
    """List all tasks."""
    return db.get_all_tasks()


def list_tasks_by_priority():
    """List tasks sorted by priority."""
    return db.get_tasks_sorted_by_priority()


def get_tasks_by_status(status):
    """Get tasks filtered by status."""
    return db.get_tasks_by_status(status)


def get_overdue_tasks():
    """Get all tasks that are past their due date."""
    today = date.today().isoformat()
    tasks = db.get_all_tasks()
    overdue = []
    for task in tasks:
        # BUG 4: Wrong comparison direction — gets FUTURE tasks, not overdue
        if task["due_date"] > today:
            overdue.append(task)
    return overdue


def assign_user_to_task(task_id, user):
    """Assign a user to a task."""
    if not db.get_task(task_id):
        raise KeyError(f"Task {task_id} not found")
    return db.assign_user(task_id, user)


def unassign_user_from_task(task_id, user):
    """Remove a user from a task."""
    return db.unassign_user(task_id, user)


def delete_task(task_id):
    """Delete a task."""
    if not db.get_task(task_id):
        raise KeyError(f"Task {task_id} not found")
    return db.delete_task(task_id)


def get_task_assignments(task_id):
    """Get users assigned to a task."""
    return db.get_assignments(task_id)


def update_status(task_id, status):
    """Update a task's status."""
    if not db.get_task(task_id):
        raise KeyError(f"Task {task_id} not found")
    return db.update_task_status(task_id, status)

