"""HTTP/API layer for task tracker.
This module provides high-level API functions that parse inputs
and delegate to the service layer.
"""
import service


def api_create_task(data):
    """Create a task from API data dict.
    data keys: title, priority, due_date, status
    """
    title = data.get("title", "")
    priority = data.get("priority", "medium")
    due_date = data.get("due_date", "")
    status = data.get("status", "open")
    task_id = service.create_task(title, priority, due_date, status)
    return {"status": "ok", "task_id": task_id}


def api_get_task(task_id):
    """Get a single task."""
    task = service.get_task(task_id)
    return {"status": "ok", "task": task}


def api_list_tasks(sort_by=None):
    """List tasks, optionally sorted."""
    if sort_by == "priority":
        tasks = service.list_tasks_by_priority()
    else:
        tasks = service.list_tasks()
    return {"status": "ok", "tasks": tasks}


def api_get_tasks_by_status(status):
    """Get tasks by status."""
    tasks = service.get_tasks_by_status(status)
    return {"status": "ok", "tasks": tasks}


def api_get_overdue_tasks():
    """Get overdue tasks."""
    tasks = service.get_overdue_tasks()
    return {"status": "ok", "tasks": tasks}


def api_assign_user(task_id, user):
    """Assign a user to a task."""
    service.assign_user_to_task(task_id, user)
    return {"status": "ok"}


def api_unassign_user(task_id, user):
    """Unassign a user from a task."""
    service.unassign_user_from_task(task_id, user)
    return {"status": "ok"}


def api_delete_task(task_id):
    """Delete a task."""
    service.delete_task(task_id)
    return {"status": "ok"}


def api_get_assignments(task_id):
    """Get assignments for a task."""
    users = service.get_task_assignments(task_id)
    return {"status": "ok", "users": users}


def api_update_status(task_id, status):
    """Update a task's status."""
    service.update_status(task_id, status)
    return {"status": "ok"}
